settings.custom_liquid:
{%- comment -%}
CozzyPaws • Blog moderne (Custom Liquid compatible)
- Hero simple + recherche client-side
- Tags cliquables (mènent vers /tagged/<tag>)
- Grille responsive "card" (limite d’articles configurable)
- Aucune pagination ni schema (OK pour bloc Liquid personnalisé)
{%- endcomment -%}

{%- assign blog_title = 'Conseils & Éducation' -%}
{%- assign blog_subtitle = 'Éducation, bien-être et astuces pour vos compagnons' -%}
{%- assign show_search = true -%}
{%- assign show_tags = true -%}
{%- assign articles_limit = 12 -%}

<section class="cp-blog" style="--cp:#521010; --ink:#1e1e1e; --muted:#6b6b6b; --card:#ffffff;">
  {%- if blog -%}
  <!-- Hero -->
  <div class="page-width cp-hero">
    <div class="cp-hero-left">
      <h1 class="cp-title">{{ blog_title | default: blog.title }}</h1>
      <p class="cp-sub">{{ blog_subtitle }}</p>
    </div>
    <div class="cp-hero-right">
      {%- if show_search -%}
      <label class="cp-search">
        <input id="cpBlogSearch" type="search" placeholder="Rechercher un article…" aria-label="Recherche blog">
        <svg viewBox="0 0 24 24" width="18" height="18" aria-hidden="true"><path d="M10 4a6 6 0 1 1 0 12 6 6 0 0 1 0-12Zm0-2a8 8 0 1 0 0 16 8 8 0 0 0 0-16Zm12.71 19.29-4.4-4.4a1 1 0 1 0-1.42 1.42l4.4 4.4a1 1 0 0 0 1.42-1.42Z" fill="currentColor"/></svg>
      </label>
      {%- endif -%}
    </div>
  </div>

  <!-- Tags -->
  {%- if show_tags and blog.tags.size > 0 -%}
  <div class="page-width cp-tags">
    {%- for tag in blog.tags -%}
      <a class="cp-tag" href="{{ blog.url }}/tagged/{{ tag | handleize }}">{{ tag }}</a>
    {%- endfor -%}
  </div>
  {%- endif -%}

  <!-- Grid -->
  <div class="page-width">
    <div id="cpBlogGrid" class="cp-grid">
      {%- for article in blog.articles limit: articles_limit -%}
        {%- assign words = article.content | strip_html | split: ' ' | size -%}
        {%- assign minutes = words | plus: 199 | divided_by: 200 -%}
        <article class="cp-card"
                 data-title="{{ article.title | escape | downcase }}"
                 data-excerpt="{{ article.excerpt_or_content | strip_html | downcase }}">
          <a class="cp-media" href="{{ article.url }}" aria-label="{{ article.title | escape }}">
            {%- if article.image -%}
              <img src="{{ article.image | image_url: width: 900 }}"
                   alt="{{ article.image.alt | default: article.title | escape }}" loading="lazy">
            {%- else -%}
              <div class="cp-media-ph">CozzyPaws</div>
            {%- endif -%}
          </a>
          <div class="cp-body">
            <h2 class="cp-h2"><a href="{{ article.url }}">{{ article.title }}</a></h2>
            <p class="cp-meta">
              <time datetime="{{ article.published_at | date: '%Y-%m-%d' }}">{{ article.published_at | date: "%d %b %Y" }}</time>
              <span aria-hidden="true">•</span>
              <span>{{ minutes }} min</span>
            </p>
            <p class="cp-excerpt">
              {{ article.excerpt_or_content | strip_html | truncate: 140 }}
            </p>
            <a class="cp-cta" href="{{ article.url }}">Lire l’article</a>
          </div>
        </article>
      {%- endfor -%}
    </div>
  </div>
  {%- else -%}
    <div class="page-width" style="margin:24px auto;">
      <p>Ajoutez ce bloc sur une page de blog (ex: /blogs/news).</p>
    </div>
  {%- endif -%}
</section>

<style>
  .cp-blog{color:var(--ink);}
  .cp-hero{display:flex; align-items:flex-end; justify-content:space-between; gap:16px; padding:24px 0 8px;}
  .cp-title{margin:0; font-weight:800; font-size:clamp(1.4rem,3vw,2rem);}
  .cp-sub{margin:.25rem 0 0; color:var(--muted);}
  .cp-search{position:relative; display:flex; align-items:center; gap:8px; background:#fff; border:1px solid #e7e7e7; border-radius:999px; padding:6px 10px;}
  .cp-search input{border:0; outline:0; min-width:220px; background:transparent}
  .cp-tags{display:flex; gap:8px; flex-wrap:wrap; margin:6px 0 14px;}
  .cp-tag{display:inline-block; border:1px solid #e7e7e7; padding:6px 10px; border-radius:999px; text-decoration:none; color:var(--ink); font-weight:600;}
  .cp-tag:hover{background:#fafafa}

  .cp-grid{display:grid; gap:18px; grid-template-columns:repeat(auto-fit, minmax(270px,1fr));}
  .cp-card{background:var(--card); border-radius:16px; overflow:hidden; box-shadow:0 10px 24px rgba(0,0,0,.06); display:flex; flex-direction:column; transition:transform .18s ease, box-shadow .18s ease;}
  .cp-card:hover{transform:translateY(-2px); box-shadow:0 16px 34px rgba(0,0,0,.08);}
  .cp-media{display:block; position:relative;}
  .cp-media img{width:100%; height:auto; display:block; aspect-ratio: 16 / 9; object-fit: cover;}
  .cp-media-ph{height:180px; display:flex; align-items:center; justify-content:center; background:#f4f2ef; color:#777;}
  .cp-body{padding:14px; display:flex; flex-direction:column; gap:8px; flex:1;}
  .cp-h2{margin:.1rem 0; font-size:1.05rem;}
  .cp-h2 a{color:inherit; text-decoration:none;}
  .cp-h2 a:hover{text-decoration:underline;}
  .cp-meta{margin:0; color:var(--muted); font-size:.9rem; display:flex; gap:8px; align-items:center;}
  .cp-excerpt{margin:.1rem 0 .25rem; color:#3a3a3a;}
  .cp-cta{align-self:flex-start; background:var(--cp); color:#fff; padding:.5rem .8rem; border-radius:999px; text-decoration:none; font-weight:800;}
  .cp-cta:hover{opacity:.92;}
  @media (max-width: 749px){ .cp-search input{min-width:140px;} }
</style>

<script>
  (function(){
    var q = document.getElementById('cpBlogSearch');
    if(!q) return;
    var grid = document.getElementById('cpBlogGrid');
    if(!grid) return;
    var cards = grid.querySelectorAll('.cp-card');
    q.addEventListener('input', function(){
      var term = (q.value || '').toLowerCase().trim();
      cards.forEach(function(card){
        var t = card.getAttribute('data-title') || '';
        var e = card.getAttribute('data-excerpt') || '';
        var show = !term || t.indexOf(term) > -1 || e.indexOf(term) > -1;
        card.style.display = show ? '' : 'none';
      });
    });
  })();
</script>
